#!/bin/bash

source ${HOME}/miniconda3/etc/profile.d/conda.sh
conda activate rocprofiler-compute

BASE_DIR=${HOME}/workspace/ici-workspace/ici-bench
BIN_DIR=${BASE_DIR}/bin

# set workload dir to current directory's workloads
WORKLOAD_DIR=workloads

# List of all executables generated by the Makefile
TARGETS=(
  "l1_lat_a_4096_r_4096"
  "l1_lat_a_4096_r_8192"
  "l1_lat_focused_a_4096_r_4096"
  "l1_lat_focused_a_4096_r_8192"
  "l1_lat_coal_a_4096_r_4096"
  "l1_lat_coal_a_4096_r_8192"
  "l1_lat_uncoal_a_4096_r_4096_s_2"
  "l1_lat_uncoal_a_4096_r_8192_s_2"
  "l1_lat_uncoal_a_4096_r_4096_s_4"
  "l1_lat_uncoal_a_4096_r_8192_s_4"
  "l1_lat_uncoal_a_4096_r_4096_s_8"
  "l1_lat_uncoal_a_4096_r_8192_s_8"
  "l1_lat_uncoal_a_4096_r_4096_s_16"
  "l1_lat_uncoal_a_4096_r_8192_s_16"
  "l1_lat_uncoal_a_4096_r_4096_s_32"
  "l1_lat_uncoal_a_4096_r_8192_s_32"
  "l1_lat_uncoal_a_4096_r_4096_s_64"
  "l1_lat_uncoal_a_4096_r_8192_s_64"
)

# Loop through each target and run profiling and analysis
for TARGET in "${TARGETS[@]}"; do
  echo "Profiling and analyzing ${TARGET}..."
  rocprof-compute profile -n ${TARGET} -- ${BIN_DIR}/${TARGET}
  rocprof-compute analyze -p ${WORKLOAD_DIR}/${TARGET}/MI300X_A1/ -k 0 > ${WORKLOAD_DIR}/${TARGET}/MI300X_A1/analyze.out
done